(function(){let expresion="",pila=[];const container=document.createElement("div");container.className="container";const calc=document.createElement("div");calc.className="calculadora";const pantalla=document.createElement("div");pantalla.className="pantalla",pantalla.textContent="0";const botones=document.createElement("div");botones.className="botones";const valores=[["AC","rojo"],["C","naranja"],["←","naranja"],["÷","azul"],["(","morado"],[")","morado"],["x","morado"],["y","morado"],["7","numero"],["8","numero"],["9","numero"],["*","azul"],["4","numero"],["5","numero"],["6","numero"],["-","azul"],["1","numero"],["2","numero"],["3","numero"],["+","azul"],["0","numero"],[".","numero"],["=","verde"],["Evaluar","verde"]];valores.forEach(([texto,clase])=>{const btn=document.createElement("button");btn.textContent=texto,btn.className=clase,btn.onclick=()=>{if("AC"===texto)expresion="",pantalla.textContent="0";else if("C"===texto)expresion="",pantalla.textContent="0";else if("←"===texto)expresion=expresion.slice(0,-1),pantalla.textContent=expresion||"0";else if("="===texto||"Evaluar"===texto)try{let resultado=eval(expresion.replace("÷","/"));pila.push(expresion+" = "+resultado),expresion=resultado.toString(),pantalla.textContent=expresion,mostrarHistorial()}catch{pantalla.textContent="Error",expresion=""}else expresion+=texto,pantalla.textContent=expresion},botones.appendChild(btn)}),calc.appendChild(pantalla),calc.appendChild(botones);const hist=document.createElement("div");hist.className="historial";const titulo=document.createElement("h3");titulo.textContent="Historial";const lista=document.createElement("div");function mostrarHistorial(){lista.innerHTML="",pila.slice().reverse().forEach(e=>{const t=document.createElement("div");t.textContent=e,lista.appendChild(t)})}hist.appendChild(titulo),hist.appendChild(lista),container.appendChild(calc),container.appendChild(hist),document.body.appendChild(container)})();